from flask import Flask, request
import xml.etree.ElementTree as ET
app = Flask(__name__)


@app.route('/saml', methods=['POST'])
def saml():
    # Parse the XML response from the SAML assertion
    tree = ET.parse(request.data)

    # Get the root element of the XML document
    root = tree.getroot()

    # Check that the root element is a Response element
    if root.tag != 'Response':
        return "Invalid response"

    # Iterate through each child element in the root element
    for child in root:

        # Check whether the child element is an Assertion element
        if child.tag == 'Assertion':

            # Get the Subject element from the Assertion
            subject = child.find('Subject')

            # Check that there is a Subject element present
            if subject is None:
                return "Invalid response"

            # Iterate through each child of the Subject element
            for subchild in subject:

                # Check whether the child element is an NameID element
                if subchild.tag == 'NameID':

                    # Get the text content of the NameID
                    nameid = subchild.text

                    # Print the NameID value to the console
                    print(nameid)

    return "Success"


if __name__ == '__main__':
    app.run()